import { useEffect, useState } from "react";

function LoadingScreenAnimation({ onComplete }) {
  const [text, setText] = useState("");
  const [progress, setProgress] = useState(0);

  const fullText = "Loading Portfolio";

  useEffect(() => {
    let index = 0;
    const textInterval = setInterval(() => {
      setText(fullText.substring(0, index));
      setProgress((index / fullText.length) * 100);
      index++;

      if (index > fullText.length) {
        clearInterval(textInterval);
        setTimeout(() => {
          onComplete();
        }, 800);
      }
    }, 120);

    return () => clearInterval(textInterval);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 z-50 bg-gradient-to-br from-black via-gray-900 to-gray-800 text-white flex flex-col items-center justify-center gap-8">
      {/* Decorative elements */}
      <div className="decorative-circle circle-1"></div>
      <div className="decorative-circle circle-2"></div>
      <div className="decorative-circle circle-3"></div>

      <div className="flex flex-col items-center gap-6 z-10">
        <div className="text-center">
          <div className="monochrome-text text-4xl md:text-5xl font-bold mb-4">
            HELLO
          </div>
          <div className="text-lg text-gray-300">Welcome to my portfolio</div>
        </div>

        <div className="w-[300px] h-1 bg-white/10 rounded-full overflow-hidden">
          <div 
            className="h-full bg-gradient-to-r from-white via-gray-300 to-white transition-all duration-300 ease-out"
            style={{ width: `${progress}%` }}
          ></div>
        </div>

        <div className="text-2xl md:text-3xl font-semibold text-center h-12">
          {text}
          <span className="animate-blink ml-1">|</span>
        </div>

        <div className="flex gap-2 mt-4">
          {[...Array(3)].map((_, i) => (
            <div
              key={i}
              className="w-3 h-3 rounded-full bg-white animate-pulse"
              style={{ animationDelay: `${i * 0.2}s` }}
            ></div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default LoadingScreenAnimation;

import { RxCross2 } from "react-icons/rx";
import { useEffect } from "react";

function MobileMenu({ isMenuOpen, setIsMenuOpen }) {
  useEffect(() => {
    if (isMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
  }, [isMenuOpen]);

  const menuItems = [
    { label: "Home", href: "#home" },
    { label: "About", href: "#about" },
    { label: "Projects", href: "#projects" },
    { label: "Skills", href: "#skills" },
    { label: "Contact", href: "#contact" }
  ];

  return (
    <div
      className={`fixed w-full top-0 left-0 z-50 flex flex-col items-center justify-center transition-all duration-500 ease-in-out ${
        isMenuOpen
          ? "h-screen opacity-100 pointer-events-auto"
          : "h-0 opacity-0 pointer-events-none"
      }`}
      style={{
        background: 'rgba(15, 12, 41, 0.95)',
        backdropFilter: 'blur(10px)'
      }}
    >
      <button
        onClick={() => setIsMenuOpen(false)}
        className="absolute top-6 right-6 text-2xl p-2 rounded-full bg-glass hover:bg-white/20 transition-colors duration-300 focus:outline-none"
        aria-label="Close Menu"
      >
        <RxCross2 className="text-white" />
      </button>

      <div className="flex flex-col items-center gap-8">
        {menuItems.map((item, index) => (
          <a
            key={item.label}
            onClick={() => setIsMenuOpen(false)}
            href={item.href}
            className={`text-3xl font-bold transform transition-all duration-700 ${
              isMenuOpen
                ? "opacity-100 translate-y-0"
                : "opacity-0 translate-y-8"
            }`}
            style={{
              transitionDelay: isMenuOpen ? `${index * 100 + 300}ms` : '0ms',
              background: 'linear-gradient(45deg, #ff6b6b, #4d96ff)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              backgroundClip: 'text'
            }}
          >
            {item.label}
          </a>
        ))}
      </div>

      <div className="absolute bottom-8 text-gray-400 text-sm">
        Navigate through portfolio
      </div>
    </div>
  );
}

export default MobileMenu;

import { useEffect, useState } from "react";
import Logo from "./Logo";
import { MdMenu } from "react-icons/md";

function Navbar({ isMenuOpen, setIsMenuOpen }) {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    document.body.style.overflow = isMenuOpen ? "hidden" : "";

    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [isMenuOpen]);

  const navItems = [
    { label: "Home", href: "#home" },
    { label: "About", href: "#about" },
    { label: "Projects", href: "#projects" },
    { label: "Skills", href: "#skills" },
    { label: "Contact", href: "#contact" }
  ];

  return (
    <nav className={`fixed top-0 w-full z-40 transition-all duration-300 ${
      scrolled 
        ? 'bg-glass-dark py-2 shadow-xl' 
        : 'bg-transparent py-4'
    }`}>
      <div className="max-w-7xl mx-auto px-6">
        <div className="flex justify-between items-center h-16">
          <Logo />

          <button
            onClick={() => setIsMenuOpen(true)}
            className="md:hidden text-2xl p-2 rounded-lg bg-glass hover:bg-white/20 transition-colors duration-300 focus:outline-none"
            aria-label="Open Menu"
          >
            <MdMenu className="text-white" />
          </button>

          <div className="hidden md:flex items-center space-x-1">
            {navItems.map((item) => (
              <a
                key={item.label}
                href={item.href}
                className="px-4 py-2 rounded-lg text-gray-300 hover:text-white hover:bg-white/10 transition-all duration-300 font-medium relative group"
              >
                {item.label}
                <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-gradient-to-r from-[#ff6b6b] to-[#4d96ff] transition-all duration-300 group-hover:w-full"></span>
              </a>
            ))}
            <a
              href="#contact"
              className="ml-4 px-6 py-2 rounded-full btn-primary font-semibold transition-all duration-300 hover:scale-105"
            >
              Get in Touch
            </a>
          </div>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;

import { useEffect, useRef, useState } from "react";

function RevealOnScroll({ children, delay = 0, threshold = 0.2 }) {
  const ref = useRef(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setTimeout(() => {
            setIsVisible(true);
          }, delay);
        }
      },
      { 
        threshold,
        rootMargin: "0px 0px -50px 0px"
      }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => observer.disconnect();
  }, [delay, threshold]);

  return (
    <div 
      ref={ref} 
      className={`reveal ${isVisible ? 'visible' : ''}`}
      style={{
        transitionDelay: `${delay}ms`
      }}
    >
      {children}
    </div>
  );
}

export default RevealOnScroll;

import { useState } from "react";
import { motion } from "framer-motion";
import axios from "axios";
import personalData from "../assets/personalData.json"; // store your info here

export default function ChatbotOverlay() {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  // const GEMINI_API_KEY = #; // ΓÜá∩╕Å This will be visible to everyone

  const sendMessage = async () => {
    if (!input.trim()) return;

    const newMsg = { sender: "user", text: input };
    setMessages(prev => [...prev, newMsg]);
    setInput("");
    setLoading(true);

    // 1∩╕ÅΓâú Check if it's about you
    const keywords = ["you", "your", "portfolio", "project", "skill"];
    if (keywords.some(k => input.toLowerCase().includes(k))) {
      setMessages(prev => [...prev, { sender: "bot", text: `HereΓÇÖs info about me: ${JSON.stringify(personalData)}` }]);
      setLoading(false);
      return;
    }

    // 2∩╕ÅΓâú Fetch latest info from Gemini
    try {
      const res = await axios.post(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-pro:generateContent?key=${GEMINI_API_KEY}`,
        {
          contents: [{ role: "user", parts: [{ text: input }] }]
        }
      );
      const reply = res.data?.candidates?.[0]?.content?.parts?.[0]?.text || "I couldn't find info.";
      setMessages(prev => [...prev, { sender: "bot", text: reply }]);
    } catch {
      setMessages(prev => [...prev, { sender: "bot", text: "Error fetching latest info." }]);
    }
    setLoading(false);
  };

  return (
    <>
      <motion.div
        className="fixed bottom-6 right-6 bg-blue-600 text-white p-4 rounded-full cursor-pointer shadow-lg"
        onClick={() => setOpen(!open)}
        whileHover={{ scale: 1.1 }}
      >
        ≡ƒÆ¼
      </motion.div>

      {open && (
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          animate={{ opacity: 1, y: 0 }}
          className="fixed bottom-20 right-6 w-80 bg-white shadow-lg rounded-lg flex flex-col"
        >
          <div className="p-3 bg-blue-600 text-white rounded-t-lg">Chat with me</div>
          <div className="flex-1 p-3 overflow-y-auto max-h-80">
            {messages.map((msg, i) => (
              <div key={i} className={`my-2 ${msg.sender === "user" ? "text-right" : "text-left"}`}>
                <span className={`inline-block p-2 rounded-lg ${msg.sender === "user" ? "bg-blue-200" : "bg-gray-200"}`}>
                  {msg.text}
                </span>
              </div>
            ))}
            {loading && <div className="text-gray-500 text-sm">Thinking...</div>}
          </div>
          <div className="flex border-t">
            <input
              className="flex-1 p-2 outline-none bg-green-600"
              value={input}
              onChange={e => setInput(e.target.value)}
              placeholder="Ask me something..."
              onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            />
            <button onClick={sendMessage} className="px-4 bg-blue-600 text-white">Send</button>
          </div>
        </motion.div>
      )}
    </>
  );
}
